/* ---- main app ---- */
 /* ═══════════════════════════════════════════*/ /* DATA*/ /* ═══════════════════════════════════════════*/ const SETS = [ { label:"Set 1 — Diabetes & COPD", rps:[ { id:"1a", label:"RP1 — Type 2 Diabetes", setting:"GP Clinic · Greenfield Medical Centre", patient:"Mr. David Hargreaves, 48", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"pNInz6obpgDQGcFmaJgB",openai:"echo"}, task_card:{ title:"Role Play 1 — Type 2 Diabetes (Newly Diagnosed)", setting:"Outpatient GP Clinic · Greenfield Medical Centre", patient:"Mr. David Hargreaves, 48", you:"A GP at Greenfield Medical Centre.", background:"Routine blood test results: HbA1c 8.2% (normal <5.7%), fasting glucose 9.4 mmol/L, BMI 31.2. Patient came for routine follow-up and does not yet know the diagnosis.", tasks:["Greet and establish rapport","Sensitively communicate Type 2 diabetes diagnosis","Explain what T2DM is in plain language","Explain HbA1c result","Discuss lifestyle changes (diet, exercise, weight)","Introduce Metformin — explain how to take it","Address concern about injections/insulin","Address concern about driving licence","Arrange follow-up in 6–8 weeks"], note:"Do NOT give prognosis. Patient is likely to express shock and denial. Patient-centred approach essential." }, lines:[ {s:"Doctor",instr:"warm and welcoming, friendly GP tone, doctor initiates",t:"Good morning, Mr. Hargreaves. Please come in and have a seat. It's good to see you. How have you been feeling generally over the past few weeks? Any new symptoms — tiredness, thirst, or needing the bathroom more often than usual?"}, {s:"Patient",instr:"casual, relaxed, not worried at all",t:"Morning, Doctor. I feel absolutely fine, honestly. My wife kept nagging me to get a check-up so here I am. I assume everything's normal?"}, {s:"Doctor",instr:"calm, warm, beginning to redirect gently",t:"I'm glad you came in. I do want to go through your blood test results with you today, because some of them have come back in a range that I'm concerned about. I want to explain everything clearly and we'll work through it together. Is that okay?"}, {s:"Patient",instr:"slightly tense now, guarded",t:"...Sure. Go on then."}, {s:"Doctor",instr:"clear and compassionate, deliberate pace, pausing after the diagnosis",t:"Your results show that your blood sugar levels are significantly higher than they should be. A marker called HbA1c — which reflects your average blood sugar over the last three months — came back at 8.2%, when normal is below 5.7%. Based on this, Mr. Hargreaves, I'm diagnosing you with Type 2 diabetes. I know that's a lot to hear. How are you feeling right now?"}, {s:"Patient",instr:"shocked and defensive, slightly raised voice",t:"Diabetes? That can't be right — I feel completely fine. Surely it's a mistake? Can't you just re-run the test?"}, {s:"Doctor",instr:"steady and empathetic, firm but kind",t:"I completely understand that reaction, and I want to acknowledge how shocking this feels. But the results have been reviewed carefully — two separate markers both show the same picture. I want you to hear something important though: Type 2 diabetes is very manageable. This is not a death sentence. Many people live completely normal lives with it. But we do need to act on it now."}, {s:"Patient",instr:"quieter, processing, genuinely curious",t:"So... what is it exactly? Is it the kind where I need injections?"}, {s:"Doctor",instr:"clear, educational, reassuring about injections",t:"Great question. Type 2 diabetes is where your body either doesn't make enough insulin — the hormone that controls blood sugar — or doesn't respond to it properly. The result is sugar building up in your bloodstream. As for injections — no, we're not at that stage at all. For most newly diagnosed patients we start with a tablet called Metformin, alongside lifestyle changes. Insulin is only considered much later, and it's not inevitable."}, {s:"Patient",instr:"slightly resistant, stressed about work",t:"Okay... what kind of lifestyle changes? I work 60-hour weeks. I don't have time for the gym."}, {s:"Doctor",instr:"practical, realistic, not preachy",t:"I hear you, and I'm not going to give you an unrealistic plan. You don't need to run marathons. Even 30 minutes of brisk walking five days a week makes a measurable difference. For diet, the biggest impact comes from cutting refined carbs — white bread, white rice, sugary drinks. I'd like to refer you to a dietitian who can work around your schedule. And even a 5 to 10 percent weight reduction can dramatically improve your levels."}, {s:"Patient",instr:"new specific worry emerging",t:"What about my driving? I drive a lot for work. Can I lose my licence?"}, {s:"Doctor",instr:"reassuring, matter of fact",t:"That's a very important question. The good news is that most people with Type 2 diabetes on Metformin alone can continue driving without restriction. You'll need to notify the licensing authority — that's standard — but there's no reason to expect you'll lose your licence at this stage."}, {s:"Patient",instr:"relieved, more cooperative now",t:"That's a relief. So what happens next?"}, {s:"Doctor",instr:"organised and forward-looking, positive close",t:"I'll start you on a low dose of Metformin today. I'm also referring you to a dietitian and a diabetes education programme. I'd like to see you back in six to eight weeks to recheck your bloods. If anything concerns you before then — call us. You've done the right thing by coming in today, and we're going to support you through this."}, ] }, { id:"1b", label:"RP2 — COPD Smoking Relapse", setting:"Respiratory Clinic · St. Clement's Hospital", patient:"Mrs. Patricia O'Brien, 61", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"Xb7hH8MSUJpSbSDYk0k2",openai:"nova"}, task_card:{ title:"Role Play 2 — COPD Review: Smoking Relapse", setting:"Outpatient Respiratory Clinic · St. Clement's Hospital", patient:"Mrs. Patricia O'Brien, 61", you:"A Respiratory Physician seeing Mrs. O'Brien for a 6-month review.", background:"Known COPD, ex-smoker (40 pack-years). FEV1 declined 58%→51% predicted. Two exacerbations this year. Has recently relapsed to smoking (2–3/day) following husband's cancer diagnosis.", tasks:["Greet and open the consultation","Explore symptoms and impact","Address smoking relapse — non-judgementally","Counsel about quitting (cessation service, varenicline)","Discuss spirometry decline and implications","Address fear of home oxygen","Review inhaler regimen (step up)","Introduce pulmonary rehabilitation","Arrange 3-month follow-up"], note:"Do NOT be judgmental about smoking relapse. Address home oxygen fear directly. Patient-centred throughout." }, lines:[ {s:"Doctor",instr:"warm and welcoming, unhurried — doctor initiates",t:"Mrs. O'Brien, lovely to see you. Come in and sit down. Before we look at any results, I'd like to hear from you first — how have you been since your last visit six months ago? How's your breathing day to day?"}, {s:"Patient",instr:"tired, subdued, heavy",t:"Not great, honestly. I'm more breathless than before. Even the stairs are a struggle. And I had two bad flare-ups this year — both needed antibiotics and steroids. It's been a tough year."}, {s:"Doctor",instr:"empathetic, acknowledging the difficulty",t:"I'm sorry to hear that — two exacerbations in a year is significant, and I imagine those episodes were frightening. Is there anything you wanted to bring up yourself today?"}, {s:"Patient",instr:"hesitant, guilty, voice slightly trembling",t:"Actually... yes. I have to be honest. I started smoking again. Not much — two or three a day. It started after my husband was diagnosed with cancer. I just didn't cope well."}, {s:"Doctor",instr:"non-judgmental, warm, compassionate",t:"Thank you for telling me that. I know it wasn't easy to say, and I want you to know — I'm not here to judge you. What you've been through with your husband's diagnosis is enormous. You managed three years without smoking — that took real strength. A relapse doesn't erase that. What matters is where we go from here."}, {s:"Patient",instr:"quietly relieved, surprised",t:"I thought you'd be angry with me."}, {s:"Doctor",instr:"honest but kind, measured",t:"Not at all. But I do want to be honest. Your breathing tests today show your lung function has declined — from 58 to 51 percent of what we'd expect. That's a meaningful drop in twelve months, and I think the smoking is likely contributing to it."}, {s:"Patient",instr:"frightened, voice breaking slightly",t:"Am I going to end up on home oxygen? That's my biggest fear. I don't want to be a burden to my children."}, {s:"Doctor",instr:"steady, honest but hopeful",t:"I want to take that fear seriously. You're not at that stage yet, and home oxygen is not inevitable. The most powerful thing you can do right now is stop smoking again — even two or three a day is enough to accelerate the damage. Stopping now will significantly slow the progression. Would you be open to talking about quitting again?"}, {s:"Patient",instr:"conflicted, exhausted",t:"I know I have to. I just don't know if I have the strength with everything going on with my husband."}, {s:"Doctor",instr:"gentle, supportive, practical",t:"And that's completely understandable. You don't have to do this alone. I'd like to refer you to our smoking cessation service — they're trained specifically for people who've relapsed, and they can offer medication like nicotine replacement or varenicline, which makes quitting much easier than willpower alone. We'd do this at your pace."}, {s:"Patient",instr:"more engaged, practical",t:"Okay. I'm willing to try. What about my inhalers? They don't seem to be working as well."}, {s:"Doctor",instr:"clinical but warm, explaining the plan",t:"Are you using your blue reliever inhaler more often?"}, {s:"Patient",instr:"matter of fact",t:"Yes — almost every day now. Sometimes twice."}, {s:"Doctor",instr:"clear, confident, outlining next steps",t:"That tells me you need more baseline support. I'm going to add a long-acting bronchodilator — it works over 24 hours to keep your airways open, rather than just rescuing you in the moment. I'll also give you a written action plan for flare-ups. And I'd strongly recommend pulmonary rehabilitation — a supervised programme that patients consistently say makes a real difference, physically and emotionally. I'd like to see you back in three months. You've been through a very hard year, Mrs. O'Brien. The fact that you were honest with me today — that takes courage."}, {s:"Patient",instr:"quietly grateful, emotional",t:"Thank you, Doctor. I feel better just for having talked about it. I'll do my best."}, ] } ] }, { label:"Set 2 — Depression & AF", rps:[ { id:"2a", label:"RP1 — Depression", setting:"GP Clinic · Westfield Medical Centre", patient:"Mr. Kevin Walsh, 35", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"pNInz6obpgDQGcFmaJgB",openai:"echo"}, task_card:{ title:"Role Play 1 — Depression (New Presentation)", setting:"GP Clinic · Westfield Medical Centre", patient:"Mr. Kevin Walsh, 35 (software developer)", you:"A GP at Westfield Medical Centre.", background:"Mr. Walsh presents with 3-month history of fatigue and poor sleep. His wife encouraged him to attend. No prior mental health history. Currently working long hours on a major project.", tasks:["Greet and establish rapport","Explore symptoms and impact on daily life","Screen for depression (PHQ-9 approach)","Ask sensitively about suicidal ideation","Explain diagnosis of depression in non-stigmatising language","Address resistance to the 'depression' label","Discuss CBT and antidepressants as options","Address concern that antidepressants are addictive","Provide safety net and arrange 2-week follow-up"], note:"MUST ask about suicidal ideation sensitively but directly. Patient is resistant to mental health label. Non-stigmatising language essential throughout." }, lines:[ {s:"Doctor",instr:"warm, friendly GP tone, doctor initiates — genuine and unhurried",t:"Good morning, Mr. Walsh. I'm Dr. Peterson — come in, have a seat. It's good to meet you. Your wife encouraged you to come in, I understand. How are you feeling today?"}, {s:"Patient",instr:"awkward, guarded, downplaying symptoms",t:"I'm alright, I suppose. A bit tired. My wife basically dragged me here, honestly. I keep telling her it's just work stress."}, {s:"Doctor",instr:"warm, gently drawing him out",t:"I'm glad you came. Can you tell me a bit more about the tiredness — when did it start and how would you describe it?"}, {s:"Patient",instr:"gradually opening up, flat",t:"Three or four months? I wake up already exhausted. The sleep isn't doing anything. And I've just... stopped enjoying things. Gaming, the gym — I haven't been in months."}, {s:"Doctor",instr:"attentive, picking up the key phrase",t:"Stopped enjoying things — that's important. Can you say more? What does a typical day feel like for you?"}, {s:"Patient",instr:"honest, slightly embarrassed, searching",t:"Just flat. Like everything is grey. I'm not sad exactly, just... nothing much. My wife says I've become a different person. My concentration at work is terrible too — I keep making mistakes."}, {s:"Doctor",instr:"empathetic, then sensitively asking about suicidal ideation",t:"Thank you for sharing that. I want to ask you something I ask all patients going through a difficult time — and it's a routine question, not a judgement. Have you had any thoughts of harming yourself, or that life isn't worth living?"}, {s:"Patient",instr:"surprised but not offended, honest",t:"No — no, nothing like that. I'm not at that point. I just feel stuck. Like I can't shake this fog."}, {s:"Doctor",instr:"reassured, moving forward carefully",t:"I'm glad you told me that. Mr. Walsh, what you've described — the low mood, losing enjoyment, fatigue, poor concentration over months — these are recognisable symptoms, and I want to talk to you about what I think is going on. I believe you're experiencing depression. I know that word can feel heavy, so I want to explain what I mean."}, {s:"Patient",instr:"defensive, resistant to the label",t:"Depression? I don't know — I still go to work every day. I'm functioning. Is it not just tiredness?"}, {s:"Doctor",instr:"non-stigmatising, educational, gently challenging",t:"That's a very common misconception, and I'm glad you raised it. Depression doesn't always look like the most severe picture you might imagine. Going through the motions, feeling disconnected, losing your spark — this is depression. It's not weakness or a character flaw. It's a medical condition, like hypertension or diabetes, and it has very effective treatments."}, {s:"Patient",instr:"processing, hesitant, a specific worry",t:"So do I have to go on antidepressants? My mate says they're addictive."}, {s:"Doctor",instr:"clear and direct, correcting the misconception",t:"That's one of the most common concerns I hear, so let me be direct: antidepressants are not addictive. They don't cause cravings or dependency. Some people experience discontinuation effects if they stop too quickly — which is why we taper slowly — but taken properly, they're safe and well-tolerated. That said, medication is one option, not the only one. I'd actually suggest starting with a talking therapy called CBT — cognitive behavioural therapy — which has excellent evidence for depression."}, {s:"Patient",instr:"curious, warming slightly",t:"What's that? Like seeing a therapist? How long does it take?"}, {s:"Doctor",instr:"practical, explaining CBT simply",t:"Yes — it's structured, usually six to twelve sessions, where you work with a therapist to understand how your thoughts and feelings connect, and develop practical strategies to break unhelpful patterns. You can self-refer through an NHS talking therapies service and usually start within a few weeks. If things don't improve after four to six weeks, we'd reassess and consider medication. I'd like to see you back in two weeks. And if things get worse before then — please call us the same day."}, {s:"Patient",instr:"more settled, genuinely surprised",t:"Yeah. I think I can try that. I feel a bit better just having talked about it, actually."}, {s:"Doctor",instr:"warm, genuine, encouraging close",t:"That's really good to hear. Please tell your wife she was right to encourage you — coming in was the first step. I'll print the self-referral form before you leave. Take care of yourself, Mr. Walsh."}, ] }, { id:"2b", label:"RP2 — Atrial Fibrillation", setting:"Cardiology Clinic · St. Raphael's Hospital", patient:"Mrs. Dorothy Chen, 68", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"Xb7hH8MSUJpSbSDYk0k2",openai:"marin"}, task_card:{ title:"Role Play 2 — Atrial Fibrillation (New Diagnosis)", setting:"Cardiology Outpatient Clinic · St. Raphael's Hospital", patient:"Mrs. Dorothy Chen, 68 (retired teacher)", you:"A Cardiology Registrar.", background:"Incidental AF on routine ECG. History of hypertension (amlodipine) and mild T2DM. No prior cardiac history. Travels internationally 2–3x/year to visit family. Currently asymptomatic.", tasks:["Greet and reassure","Explain what AF is in plain language","Explain stroke risk clearly without causing panic","Introduce anticoagulation (apixaban/DOAC) — benefits","Address concern about bleeding risk","Address concern about international travel","Discuss lifestyle factors (alcohol, caffeine, sleep, exercise)","Arrange echocardiogram and Holter monitor","Follow-up in 6 weeks"], note:"Do NOT imply stroke is imminent. Avoid unexplained jargon (NOAC, CHA2DS2-VASc). Patient is anxious but cooperative." }, lines:[ {s:"Doctor",instr:"warm, calm, doctor initiates — welcoming and unhurried",t:"Good afternoon, Mrs. Chen. I'm Dr. Harrison, one of the cardiology registrars. Please come in and sit down. Thank you for coming. I understand your GP referred you after picking something up on your ECG. Before anything else — how are you feeling in yourself?"}, {s:"Patient",instr:"nervous but composed, slightly worried",t:"I feel fine, honestly. That's what's confusing me. The doctor just said something was irregular and sent me here. I've been quite worried since then."}, {s:"Doctor",instr:"reassuring, beginning to explain",t:"That's completely understandable, and I want to start by putting your mind at ease on one thing — you feel well, you came in at the right time, and what we're dealing with is very manageable. Your ECG showed something called atrial fibrillation — AF for short. Have you heard of it?"}, {s:"Patient",instr:"honest, attentive, anxious",t:"I've heard the words but I don't know what it means. Is it serious?"}, {s:"Doctor",instr:"clear, educational, calm pace, good analogy",t:"Let me explain simply. Your heart normally beats in a very organised rhythm — like a well-conducted orchestra. In AF, the upper chambers start firing in a chaotic, irregular way. Your heart is beating at a normal speed, but the rhythm is irregular. That's what the ECG picked up."}, {s:"Patient",instr:"absorbing it, then the key question",t:"And is that dangerous? What does it mean for me day to day?"}, {s:"Doctor",instr:"honest but measured, explaining stroke risk without panic",t:"I want to answer that honestly. AF itself doesn't usually cause immediate danger — many people with AF live normal, active lives. The main concern is that when the upper chambers aren't squeezing properly, blood can pool there and form small clots. If a clot travels to the brain, it can cause a stroke. That's why we take AF seriously and why we're seeing you today."}, {s:"Patient",instr:"frightened, voice tightening",t:"A stroke? So I'm at risk of a stroke? What are the chances?"}, {s:"Doctor",instr:"calm, contextualising, reassuring",t:"I want to put that in perspective. This is a longer-term risk, not something that will happen tomorrow — and it's a risk we can reduce significantly. We use a scoring system based on your age, blood pressure history, and diabetes, and your score is high enough that we'd recommend a medication to protect you. It reduces stroke risk by 60 to 70 percent. It's a once-daily tablet — a blood thinner called apixaban."}, {s:"Patient",instr:"worried about bleeding, a specific concern",t:"Blood thinners? My neighbour was on warfarin and was always bruising. I'm worried about that."}, {s:"Doctor",instr:"understanding, explaining the difference clearly",t:"That's a very valid concern and I hear it a lot. Warfarin — the older blood thinner — did carry more risk and needed frequent monitoring. Apixaban is a newer type that's much easier to manage, no regular blood tests needed, more predictable, and studies show it actually has a lower risk of serious bleeding than warfarin — particularly bleeding in the brain. You may notice slightly more bruising or small cuts taking longer to stop — that's expected — but serious events are uncommon."}, {s:"Patient",instr:"partially reassured, next practical question",t:"Alright. Can I ask — I travel quite a bit. I visit my daughter in Canada, my son in Australia. Will I still be able to travel?"}, {s:"Doctor",instr:"positive, reassuring, practical travel advice",t:"Absolutely — AF is no reason to stop travelling. Apixaban is available internationally. Just carry an adequate supply in your hand luggage, stay hydrated on long flights, and wear compression stockings — that's good advice for any long-haul traveller. Make sure your travel insurance is up to date and that you've declared AF — it's a manageable condition that insurers deal with all the time."}, {s:"Patient",instr:"visibly relieved, curious about lifestyle",t:"That's such a relief. Is there anything I should change? Diet, exercise?"}, {s:"Doctor",instr:"practical, positive framing",t:"Good question. Alcohol is one of the biggest triggers for AF episodes — I'd recommend keeping it minimal. Caffeine in moderation is generally fine. Sleep matters — untreated sleep apnoea is a known trigger, so if you snore heavily or wake unrefreshed, it's worth mentioning. Exercise is actually encouraged — walking, swimming, cycling. You don't need to avoid it."}, {s:"Patient",instr:"engaged, asking about next steps",t:"That's helpful. So what happens now?"}, {s:"Doctor",instr:"organised, clear plan, warm close",t:"Here's the plan. I'll start you on apixaban today with instructions on how to take it. I'll arrange an echocardiogram — an ultrasound of the heart, painless, 20 to 30 minutes — and a 24-hour Holter monitor to see how your rhythm behaves over a full day. I'd like to see you back in six weeks once we have those results. If anything worries you in the meantime, please don't hesitate to call the clinic. You've taken this all in really well, Mrs. Chen. Take care."}, {s:"Patient",instr:"settled, grateful, warm",t:"Thank you so much, Doctor. I came in quite frightened and I feel so much better. Thank you."}, ] } ] }, { label:"Set 3 — Hypertension & Thyroid", rps:[ { id:"3a", label:"RP1 — Hypertension Adherence", setting:"GP Clinic · Riverside Health Centre", patient:"Mr. Robert Okafor, 52", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"pNInz6obpgDQGcFmaJgB",openai:"echo"}, task_card:{ title:"Role Play 1 — Hypertension: Medication Non-Adherence", setting:"GP Clinic · Riverside Health Centre", patient:"Mr. Robert Okafor, 52 (secondary school teacher)", you:"A GP at Riverside Health Centre.", background:"Hypertension diagnosed 18 months ago. On amlodipine 5mg. Today's BP: 162/98 mmHg (previous: 148/92). Patient stopped medication for 3 weeks last month due to ankle swelling side effect and belief he 'didn't need it'.", tasks:["Greet and build rapport","Present today's BP reading","Sensitively explore medication adherence","Address 'I feel fine so I don't need it' belief","Explain risks of uncontrolled hypertension (stroke, MI, kidneys)","Acknowledge ankle swelling as valid side effect","Switch to ramipril — explain rationale","Discuss salt reduction and exercise","Arrange 4-week follow-up"], note:"Non-judgmental approach essential. Motivational interviewing style. Do NOT lecture. Validate the patient's experience." }, lines:[ {s:"Doctor",instr:"warm, friendly GP tone, doctor initiates",t:"Good morning, Mr. Okafor — come in, take a seat. Good to see you again. How have things been? Busy term at school?"}, {s:"Patient",instr:"relaxed, confident, slightly dismissive about health",t:"Morning, Doctor. All good — Year 11 mock exams coming up so it's hectic. But I feel absolutely fine. I'm not sure why I keep needing to come back for these checks."}, {s:"Doctor",instr:"warm, gently redirecting",t:"I'm glad you're feeling well. I do want to go through today's blood pressure reading with you, because it's something I want to talk through. The nurse recorded 162 over 98 this morning. How does that land with you?"}, {s:"Patient",instr:"surprised, defensive, downplaying",t:"162? Really? I feel completely normal. Is that not just white coat hypertension? I'm always a bit stressed coming in."}, {s:"Doctor",instr:"empathetic, acknowledging the point but honest",t:"White coat effect is real and it's a fair point. But this is actually higher than three months ago, which was already above target. And the key thing about high blood pressure is that it almost never causes symptoms — most people feel completely fine. That's exactly what makes it dangerous. May I ask — how have you been getting on with the amlodipine?"}, {s:"Patient",instr:"slightly guilty, coming clean slowly",t:"I take it mostly. But... I stopped for about three weeks last month. I just felt so well, I thought maybe I didn't need it anymore. Nothing happened."}, {s:"Doctor",instr:"non-judgmental, genuinely appreciative",t:"Thank you for being honest about that — I really mean it. A lot of patients don't say, and it means we end up adjusting the wrong things. I'm not going to lecture you. But I'd like to explain why I want you to keep taking them — because I think once you understand what's happening inside your blood vessels, it'll make more sense. Is that okay?"}, {s:"Patient",instr:"agreeable, open now",t:"Yeah — go on then."}, {s:"Doctor",instr:"clear, good analogy, not condescending",t:"Think of your blood vessels like pipes. When the pressure inside is too high for too long, it slowly damages the walls — even when you feel nothing. Over time, that damage builds up. The three things we worry most about are stroke, heart attack, and kidney damage. None of these announce themselves in advance. The tablet isn't treating symptoms — it's quietly protecting those pipes."}, {s:"Patient",instr:"genuinely absorbing this, a real shift",t:"I never thought of it that way. I always assumed if something was seriously wrong, I'd feel it. So — do you put the dose up?"}, {s:"Doctor",instr:"collaborative, exploring the real reason",t:"That's one option. But before we decide — when you stopped last month, was it really just the 'I feel fine' thinking, or was there something else?"}, {s:"Patient",instr:"honest, a specific concern emerging",t:"Actually... my ankles were a bit swollen. I didn't know if it was the tablets. That's part of why I stopped."}, {s:"Doctor",instr:"validating, explaining the side effect, offering a solution",t:"That's really important — and yes, ankle swelling is a known side effect of amlodipine. You were right to notice it. What I'd actually suggest is switching to a different type of medication altogether — an ACE inhibitor called ramipril. It works through a different mechanism, doesn't cause ankle swelling, and has the added benefit of being particularly protective for the kidneys. How does that sound?"}, {s:"Patient",instr:"noticeably more cooperative",t:"That sounds better, yeah. Will it bring my blood pressure down properly?"}, {s:"Doctor",instr:"realistic, encouraging, lifestyle point natural",t:"For most people, yes — especially combined with some lifestyle measures. Reducing salt intake makes a measurable difference — cutting added salt and processed foods. And regular moderate exercise — 30 minutes of brisk walking five days a week. I know life is busy with school and the kids, but small changes compound. I'd like to recheck your blood pressure in four weeks after the switch. Does that work?"}, {s:"Patient",instr:"settled, on board",t:"Four weeks is fine. I'll actually take them this time. I think I just needed to understand what they were doing."}, {s:"Doctor",instr:"warm, genuine close",t:"That's all I can ask. I'll send the new prescription to your pharmacy today. If you notice a dry cough — that can occasionally happen with ramipril — just give us a call. Take care of yourself, Mr. Okafor, and good luck with the Year 11 mocks."}, ] }, { id:"3b", label:"RP2 — Hypothyroidism", setting:"GP Clinic · Riverside Health Centre", patient:"Ms. Sandra Bell, 44", defDoc:{eleven:"onwK4e9ZLuTAKqWW03F9",openai:"cedar"}, defPat:{eleven:"Xb7hH8MSUJpSbSDYk0k2",openai:"marin"}, task_card:{ title:"Role Play 2 — Hypothyroidism (New Diagnosis)", setting:"GP Clinic · Riverside Health Centre", patient:"Ms. Sandra Bell, 44 (part-time accountant, lives alone)", you:"A GP discussing blood test results.", background:"TSH: 18.4 mIU/L (normal 0.4–4.0). Free T4: 8.2 pmol/L (low). Presented with 6-month history of fatigue, 6kg weight gain, feeling cold, constipation, low mood. Previously dismissed by another GP as 'just stress'.", tasks:["Greet and establish warm tone","Validate her experience — she was right that something was wrong","Explain hypothyroidism clearly in plain language","Connect diagnosis to ALL her symptoms","Explain thyroid function and what happens when underactive","Introduce levothyroxine — mechanism, how to take it","Address concern about lifelong medication","Give realistic expectation on weight loss","Explain TFT monitoring in 6–8 weeks"], note:"Patient has been dismissed before — validate strongly. She may become emotional. Do NOT promise specific weight loss outcomes." }, lines:[ {s:"Doctor",instr:"warm, attentive, doctor initiates — genuine and caring",t:"Good afternoon, Ms. Bell. I'm Dr. Crawford — please come in. Thank you for coming back in. I have your blood test results and I want to go through them with you properly. Before I do — how have you been feeling since we last spoke?"}, {s:"Patient",instr:"tired, deflated, slightly wary",t:"Honestly, not great. Still exhausted. Going to bed at nine and waking up feeling like I haven't slept. I've put on another kilo. I keep thinking something is really wrong, but I've been told before it's just stress or getting older."}, {s:"Doctor",instr:"warm and strongly validating before anything else",t:"I want to start by saying something important: you were right. Something is wrong — and the blood tests have given us a very clear answer. I'm sorry you've been dismissed before. What we found is that your thyroid gland isn't working as it should. The condition is called hypothyroidism. I'd like to explain what that means, and — importantly — what we can do about it."}, {s:"Patient",instr:"surprised, emotional, taking it in",t:"My thyroid? Is that serious? I don't really know what the thyroid does."}, {s:"Doctor",instr:"clear, educational, warm — plain language, reassurance first",t:"It's very manageable — I want to reassure you on that straightaway. Your thyroid is a small gland at the front of your neck that produces a hormone which acts like a thermostat for your whole body — it controls your metabolism, energy, temperature, digestion, and mood. When it's underactive, as yours is, that hormone is far too low. Your body's engine has been running too slowly. And that explains every symptom you've described — the fatigue, weight gain, feeling cold, constipation, low mood. All of it."}, {s:"Patient",instr:"emotional, relieved but tearful — finally validated",t:"So it wasn't in my head. I kept thinking maybe I was just lazy. Or depressed. I was starting to wonder if I was imagining it."}, {s:"Doctor",instr:"deeply empathetic, taking a moment",t:"It was absolutely not in your head. You have a real, measurable, physical condition. Your TSH is over four times the upper limit of normal. Your body has been working incredibly hard just to keep going. You weren't lazy. You were unwell. I'm really glad we found this."}, {s:"Patient",instr:"composing herself, grateful, curious",t:"Thank you. I really needed to hear that. So — is there a treatment?"}, {s:"Doctor",instr:"positive, clear, explaining levothyroxine simply",t:"Yes, and it's actually very straightforward. We replace the hormone your thyroid isn't making with a synthetic version — a tablet called levothyroxine. It's identical to the hormone your body makes naturally. You take it once a day in the morning, on an empty stomach, about 30 minutes before food or coffee — that's important because food affects absorption. One small tablet, every morning. Most people find it very easy to manage."}, {s:"Patient",instr:"a specific concern, the word 'forever' carrying weight",t:"Will I have to take it forever? The idea of being on medication for the rest of my life is quite daunting."}, {s:"Doctor",instr:"honest but compassionate, reframing positively",t:"I understand that can feel daunting. In most cases of hypothyroidism, yes — the thyroid doesn't recover on its own, so the medication is ongoing. But I'd encourage you to think of it this way: your body needs this hormone to function. The tablet simply gives it what it can no longer make itself. Millions of people take levothyroxine every day and live completely normal lives with no limitations. Once we get your dose right, it becomes just a small morning habit, nothing more."}, {s:"Patient",instr:"processing, asking the question she most cares about",t:"Will I lose the weight? I've been trying so hard and put on nearly six kilos."}, {s:"Doctor",instr:"honest and careful, not overpromising but genuinely encouraging",t:"I want to be honest rather than promise more than I can guarantee. Once your levels are normal, your metabolism will return to where it should be — so it should become easier to manage your weight through normal diet and activity. Some people do lose some of the weight they gained. But the most important changes you'll notice are your energy returning, the fatigue lifting, feeling warmer, your mood improving. Those changes make an enormous difference to quality of life."}, {s:"Patient",instr:"more settled, practical",t:"That's fair enough. How will we know the dose is right?"}, {s:"Doctor",instr:"organised, clear monitoring plan, warm close",t:"We'll repeat your thyroid blood test in six to eight weeks. It sometimes takes a small adjustment or two to find the right dose — that's normal and not something to worry about. The numbers guide us, but how you feel guides us equally. I'd like to see you back in eight weeks. I'll start you on 50 micrograms of levothyroxine today — take it every morning on an empty stomach. If you feel significantly worse before your appointment, please call us. Things should start to improve within a few weeks. Take care of yourself, Ms. Bell."}, {s:"Patient",instr:"genuinely relieved, more hopeful than she's been in months",t:"Honestly, I feel so relieved. I was starting to think I'd just feel like this forever. Knowing there's a reason, and a treatment... that means everything. Thank you."}, ] } ] } ]; const ELEVEN_VOICES=[ {id:"onwK4e9ZLuTAKqWW03F9",name:"Daniel",desc:"🇬🇧 영국 남성 ★"}, {id:"JBFqnCBsd6RMkjVDRZzb",name:"George",desc:"🇬🇧 영국 남성"}, {id:"SOYHLrjzK2X1ezoPC6cr",name:"Harry",desc:"🇬🇧 영국 남성 젊음"}, {id:"IKne3meq5aSn9XLyUdCD",name:"Charlie",desc:"🇦🇺 호주 남성"}, {id:"ZQe5CZNOzWyzPSCn5a3c",name:"James",desc:"🇦🇺 호주 남성"}, {id:"Xb7hH8MSUJpSbSDYk0k2",name:"Alice",desc:"🇬🇧 영국 여성 ★"}, {id:"pFZP5JQG7iQjIQuC4Bku",name:"Lily",desc:"🇬🇧 영국 여성"}, {id:"XrExE9yKIg1WjnnlVkGX",name:"Matilda",desc:"🇦🇺 호주 여성"}, {id:"21m00Tcm4TlvDq8ikWAM",name:"Rachel",desc:"🇺🇸 미국 여성"}, {id:"pNInz6obpgDQGcFmaJgB",name:"Adam",desc:"🇺🇸 미국 남성"}, {id:"ErXwobaYiN019PkySvjV",name:"Antoni",desc:"🇺🇸 미국 남성"}, ]; const OPENAI_VOICES=[ {id:"cedar",name:"Cedar★",desc:"고품질 남성"}, {id:"onyx",name:"Onyx",desc:"깊은 남성"}, {id:"echo",name:"Echo",desc:"자연스러운 남성"}, {id:"fable",name:"Fable",desc:"영국 남성"}, {id:"nova",name:"Nova",desc:"따뜻한 여성"}, {id:"marin",name:"Marin★",desc:"고품질 여성"}, {id:"coral",name:"Coral",desc:"친근한 여성"}, {id:"shimmer",name:"Shimmer",desc:"부드러운 여성"}, {id:"alloy",name:"Alloy",desc:"중성"}, ]; /* ═══════════════════════════════════════════*/ /* STATE*/ /* ═══════════════════════════════════════════*/ let provider=(function(){try{return localStorage.getItem("oet_provider")||"eleven"}catch(e){return "eleven"}})(), elevenKey=(function(){try{return localStorage.getItem("oet_eleven_key")||""}catch(e){return ""}})(), openaiKey=(function(){try{return localStorage.getItem("oet_openai_key")||""}catch(e){return ""}})();let docProvider=provider, patProvider=provider; let curSet=0, curRP=0; let docVoice="", patVoice=""; let cached={}, curLine=-1, curAudio=null, cancelled=false; let stability=0.55, style=0.40, sim=0.80; let timerIv=null, timerSec=180, activeBtn=null; let cardShown=false; /* ═══════════════════════════════════════════*/ /* SETUP*/ /* ═══════════════════════════════════════════*/ function selectProvider(p){ provider=p; document.getElementById("choiceEleven").className="pchoice eleven"+(p==="eleven"?" on":""); document.getElementById("choiceOpenai").className="pchoice openai"+(p==="openai"?" on":""); document.getElementById("elevenField").style.display=p==="eleven"?"block":"none"; document.getElementById("openaiField").style.display=p==="openai"?"block":"none"; checkReady(); } function checkReady(){ const ek=document.getElementById("elevenKey").value.trim(); const ok=document.getElementById("openaiKey").value.trim(); const ready=(provider==="eleven"&&ek.length>10)||(provider==="openai"&&ok.startsWith("sk-")); document.getElementById("startBtn").disabled=!ready; } function startApp(){ (function(){var _ek=document.getElementById("elevenKey");if(_ek&&_ek.value.trim())elevenKey=_ek.value.trim();var _ok=document.getElementById("openaiKey");if(_ok&&_ok.value.trim())openaiKey=_ok.value.trim();})(); /* Save to localStorage*/ try{ localStorage.setItem("oet_provider",provider); if(elevenKey) localStorage.setItem("oet_eleven_key",elevenKey); if(openaiKey) localStorage.setItem("oet_openai_key",openaiKey); }catch(e){} document.getElementById("setup").style.display="none"; document.getElementById("app").style.display="block"; initApp(); } function logout(){ document.getElementById("setup").style.display="flex"; document.getElementById("app").style.display="none"; cached={}; } /* Load saved keys /* DOMContentLoaded auto-start removed by _transform.py — boot_patch handles init * /*/ /* ═══════════════════════════════════════════*/ /* APP INIT*/ /* ═══════════════════════════════════════════*/ function initApp(){ curSet=0; curRP=0; setDefaultVoices(); buildSetTabs(); buildRPTabs(); renderCard(); buildChips(); updateInfo(); renderDial(); updateBtns(); document.getElementById("sliders").style.display=(docProvider==="eleven"||patProvider==="eleven")?"flex":"none"; } function setDefaultVoices(){ const rp=SETS[curSet].rps[curRP]; docVoice=rp.defDoc[provider]; patVoice=rp.defPat[provider]; docProvider=provider; patProvider=provider; } function buildSetTabs(){ document.getElementById("setTabs").innerHTML=SETS.map((s,i)=>` <div class="set-tab ${i===curSet?"active":""}" onclick="switchSet(${i})">${s.label}</div>`).join(""); } function buildRPTabs(){ const rps=SETS[curSet].rps; document.getElementById("rpTabs").innerHTML=rps.map((r,i)=>` <div class="rp-tab ${i===curRP?"active":""}" onclick="switchRP(${i})"> <div class="rp-tab-num">RP ${i+1}</div> <div class="rp-tab-title">${r.label}</div> </div>`).join(""); } function switchSet(i){ stopPlay(); curSet=i; curRP=0; cardShown=false; document.getElementById("taskCard").classList.remove("show"); document.getElementById("cardBtn").classList.remove("on"); document.getElementById("cardBtn").textContent="보기"; setDefaultVoices(); buildSetTabs(); buildRPTabs(); renderCard(); buildChips(); updateInfo(); renderDial(); updateBtns(); } function switchRP(i){ stopPlay(); curRP=i; cardShown=false; document.getElementById("taskCard").classList.remove("show"); document.getElementById("cardBtn").classList.remove("on"); document.getElementById("cardBtn").textContent="보기"; setDefaultVoices(); buildRPTabs(); renderCard(); buildChips(); updateInfo(); renderDial(); updateBtns(); } function updateInfo(){ const rp=SETS[curSet].rps[curRP]; document.getElementById("rpSetting").textContent=rp.setting; document.getElementById("rpPatient").textContent=rp.patient; } /* ═══════════════════════════════════════════*/ /* TASK CARD*/ /* ═══════════════════════════════════════════*/ function toggleCard(){ cardShown=!cardShown; document.getElementById("taskCard").classList.toggle("show",cardShown); const btn=document.getElementById("cardBtn"); btn.classList.toggle("on",cardShown); btn.textContent=cardShown?"숨기기":"보기"; } function renderCard(){ const tc=SETS[curSet].rps[curRP].task_card; document.getElementById("taskCard").innerHTML=` <div class="tc-ey">OET Speaking — Medicine · Candidate Card</div> <div class="tc-title">${tc.title}</div> <div class="tc-grid"> <div class="tc-bl"><div class="tc-l">Setting</div><div class="tc-v">${tc.setting}</div></div> <div class="tc-bl"><div class="tc-l">Patient</div><div class="tc-v">${tc.patient}</div></div> <div class="tc-bl"><div class="tc-l">You are</div><div class="tc-v">${tc.you}</div></div> <div class="tc-bl"><div class="tc-l">Background</div><div class="tc-v">${tc.background}</div></div> </div> <div class="tc-tasks-l">Your Tasks</div> <ul class="tc-list">${tc.tasks.map(t=>`<li>${t}</li>`).join("")}</ul> <div class="tc-note"><strong>⚠️ Note:</strong> ${tc.note}</div>`; } /* ═══════════════════════════════════════════*/ /* VOICE CHIPS*/ /* ═══════════════════════════════════════════*/ function buildChips(){ ["doc","pat"].forEach(role=>{ const cur=role==="doc"?docVoice:patVoice; const curProv=role==="doc"?docProvider:patProvider; let h=""; h+='<div style="width:100%;font-size:11px;font-weight:600;color:#94a3b8;margin:2px 0 4px;letter-spacing:.5px">ElevenLabs</div>'; h+=ELEVEN_VOICES.map(v=>`<span class="chip ${(v.id===cur&&curProv==="eleven")?"active eleven":""}" title="${v.desc}" onclick="setVoice('${role}','eleven','${v.id}')">${v.name}</span>`).join(""); h+='<div style="width:100%;font-size:11px;font-weight:600;color:#94a3b8;margin:8px 0 4px;letter-spacing:.5px">OpenAI</div>'; h+=OPENAI_VOICES.map(v=>`<span class="chip ${(v.id===cur&&curProv==="openai")?"active openai":""}" title="${v.desc}" onclick="setVoice('${role}','openai','${v.id}')">${v.name}</span>`).join(""); document.getElementById(role+"Chips").innerHTML=h; }); var _slEl=document.getElementById("sliders"); if(_slEl) _slEl.style.display=(docProvider==="eleven"||patProvider==="eleven")?"flex":"none"; if(typeof prewarmCacheFromIDB==="function")setTimeout(prewarmCacheFromIDB,0); if(typeof updateIDBBadge==="function")setTimeout(updateIDBBadge,0); } function setVoice(role,prov,v){ if(role==="doc"){docVoice=v; docProvider=prov;} else {patVoice=v; patProvider=prov;} buildChips(); renderDial(); updateBtns(); } function updateSl(t){ if(t==="stab"){stability=document.getElementById("stab").value/100;document.getElementById("stabV").textContent=stability.toFixed(2);} else if(t==="style"){style=document.getElementById("style").value/100;document.getElementById("styleV").textContent=style.toFixed(2);} else{sim=document.getElementById("sim").value/100;document.getElementById("simV").textContent=sim.toFixed(2);} } /* ═══════════════════════════════════════════*/ /* TIMER*/ /* ═══════════════════════════════════════════*/ function startTimer(sec,btnId){ clearInterval(timerIv); timerSec=sec; if(activeBtn) document.getElementById(activeBtn).classList.remove("on"); activeBtn=btnId; document.getElementById(btnId).classList.add("on"); updateTimerNum(); timerIv=setInterval(()=>{timerSec--;updateTimerNum();if(timerSec<=0)clearInterval(timerIv);},1000); } function resetTimer(){ clearInterval(timerIv); timerSec=180; if(activeBtn) document.getElementById(activeBtn).classList.remove("on"); activeBtn=null; updateTimerNum(); } function updateTimerNum(){ const m=Math.floor(timerSec/60),s=timerSec%60; const el=document.getElementById("timerNum"); el.textContent=`${m}:${s.toString().padStart(2,"0")}`; el.className="timer-num"+(timerSec<=30&&timerSec>10?" warn":timerSec<=10?" end":""); } /* ═══════════════════════════════════════════*/ /* DIALOGUE RENDER*/ /* ═══════════════════════════════════════════*/ function ckey(setI,rpI,lineI,v,prov){var _p=(prov===undefined?provider:prov);return `${setI}_${rpI}_${lineI}_${v}_${_p}`;} function renderDial(){ const lines=SETS[curSet].rps[curRP].lines; document.getElementById("dialogue").innerHTML=lines.map((l,i)=>{ const isDoc=l.s==="Doctor"; const v=isDoc?docVoice:patVoice; const _lp=isDoc?docProvider:patProvider; const key=ckey(curSet,curRP,i,v,_lp); const ok=!!cached[key]; const active=curLine===i; return ` <div class="lw ${isDoc?"doctor":"patient"}"> <div class="bubble ${isDoc?"doctor":"patient"} ${active?"active":""}" onclick="clickLine(${i})" tabindex="0"> <div class="b-role">${isDoc?"🩺 Doctor":"👤 Patient"} · ${i+1}${ok?" <span style='color:var(--green);font-size:8px'>●</span>":""}</div> <div class="b-text">${l.t}</div> ${ok?`<button class="dl-btn" onclick="dlLine(event,${i})">↓</button>`:""} </div> </div>`; }).join(""); } function updateBtns(){ const lines=SETS[curSet].rps[curRP].lines; const done=lines.filter((l,i)=>{ const v=l.s==="Doctor"?docVoice:patVoice; const _lp=l.s==="Doctor"?docProvider:patProvider; return !!cached[ckey(curSet,curRP,i,v,_lp)]; }).length; const total=lines.length; const gb=document.getElementById("genBtn"); const pb=document.getElementById("playBtn"); const db=document.getElementById("dlBtn"); if(done===total){gb.style.display="none";pb.style.display="flex";db.style.display="flex";} else{ gb.style.display="flex"; gb.textContent=done===0?`⚡ Generate All (${total})`:`⚡ Generate (${done}/${total} done)`; pb.style.display=done>0?"flex":"none"; db.style.display="none"; } } /* ═══════════════════════════════════════════*/ /* TTS API CALLS*/ /* ═══════════════════════════════════════════*/ async function ttsEleven(text, voiceId, instr){ const res=await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`,{ method:"POST", headers:{"xi-api-key":elevenKey,"Content-Type":"application/json","Accept":"audio/mpeg"}, body:JSON.stringify({ text, model_id:"eleven_turbo_v2_5", voice_settings:{stability,similarity_boost:sim,style,use_speaker_boost:true} }) }); if(!res.ok){if(res.status===401||res.status===403){try{localStorage.removeItem("oet_eleven_key");}catch(_e){}if(typeof logout==="function")logout();throw new Error("⚠️ ElevenLabs API 키가 유효하지 않습니다. 새 키를 입력해 주세요.");}const e=await res.json().catch(()=>({}));throw new Error(e.detail?.message||`ElevenLabs error ${res.status}`);} return URL.createObjectURL(await res.blob()); } async function ttsOpenai(text, voice, instr){ const body={model:"gpt-4o-mini-tts",voice,input:text,response_format:"mp3"}; if(instr) body.instructions=instr; const res=await fetch("https://api.openai.com/v1/audio/speech",{ method:"POST", headers:{"Authorization":`Bearer ${openaiKey}`,"Content-Type":"application/json"}, body:JSON.stringify(body) }); if(!res.ok){if(res.status===401||res.status===403){try{localStorage.removeItem("oet_openai_key");}catch(_e){}if(typeof logout==="function")logout();throw new Error("⚠️ OpenAI API 키가 유효하지 않습니다. 새 키를 입력해 주세요.");}const e=await res.json().catch(()=>({}));throw new Error(e.error?.message||`OpenAI error ${res.status}`);} return URL.createObjectURL(await res.blob()); } async function generateAudio(text, voice, instr, prov){ var _p=(prov===undefined?provider:prov); if(_p==="eleven"){ if(!elevenKey){ if(typeof logout==="function")logout(); throw new Error("⚠️ ElevenLabs API 키가 없습니다. 키를 입력해 주세요."); } return await ttsEleven(text,voice,instr); } if(!openaiKey){ if(typeof logout==="function")logout(); throw new Error("⚠️ OpenAI API 키가 없습니다. 키를 입력해 주세요."); } return await ttsOpenai(text,voice,instr); } /* ═══════════════════════════════════════════*/ /* GENERATE + PLAYBACK*/ /* ═══════════════════════════════════════════*/ async function generateAll(){ hideErr(); cancelled=false; const lines=SETS[curSet].rps[curRP].lines; document.getElementById("genBtn").disabled=true; showProg("gen"); for(let i=0;i<lines.length;i++){ if(cancelled)break; const l=lines[i]; const v=l.s==="Doctor"?docVoice:patVoice; const _lp=l.s==="Doctor"?docProvider:patProvider; const key=ckey(curSet,curRP,i,v,_lp); if(!cached[key]){ setProg("gen",i,lines.length,`Generating ${i+1}/${lines.length}...`); try{ cached[key]=await loadOrGenerate(key,l.t,v,l.instr||"",_lp); renderDial(); }catch(e){showErr("⚠️ "+e.message);break;} }else setProg("gen",i,lines.length,`Generating ${i+1}/${lines.length}...`); } document.getElementById("genBtn").disabled=false; hideProg(); updateBtns(); renderDial(); } async function playFrom(start){ cancelled=false; curLine=-1; hideErr(); document.getElementById("playBtn").style.display="none"; document.getElementById("stopBtn").style.display="flex"; showProg("play"); const lines=SETS[curSet].rps[curRP].lines; for(let i=start;i<lines.length;i++){ if(cancelled)break; const l=lines[i]; const v=l.s==="Doctor"?docVoice:patVoice; const _lp=l.s==="Doctor"?docProvider:patProvider; const key=ckey(curSet,curRP,i,v,_lp); let url=cached[key]; if(!url){ curLine=i; renderDial(); try{url=await loadOrGenerate(key,l.t,v,l.instr||"",_lp);cached[key]=url;renderDial();} catch(e){showErr("⚠️ "+e.message);break;} } if(cancelled)break; curLine=i; renderDial(); setProg("play",i,lines.length,`${l.s} · ${i+1}/${lines.length}`); document.getElementById("nt").textContent=`${l.s}: "${l.t.substring(0,60)}..."`; document.getElementById("np").classList.add("show"); /* scroll*/ const els=document.querySelectorAll(".lw"); if(els[i]) els[i].scrollIntoView({behavior:"smooth",block:"center"}); await new Promise(res=>{const a=new Audio(url);curAudio=a;a.onended=res;a.onerror=res;a.play().catch(res);}); if(!cancelled) await new Promise(r=>setTimeout(r,480)); } if(!cancelled){ curLine=-1; renderDial(); document.getElementById("np").classList.remove("show"); hideProg(); document.getElementById("stopBtn").style.display="none"; updateBtns(); } } function stopPlay(){ cancelled=true; if(curAudio){curAudio.pause();curAudio=null;} curLine=-1; renderDial(); document.getElementById("np").classList.remove("show"); hideProg(); document.getElementById("stopBtn").style.display="none"; updateBtns(); } function clickLine(i){stopPlay();setTimeout(()=>playFrom(i),80);} function dlLine(e,i){ e.stopPropagation(); const l=SETS[curSet].rps[curRP].lines[i]; const v=l.s==="Doctor"?docVoice:patVoice; const _lp=l.s==="Doctor"?docProvider:patProvider; const url=cached[ckey(curSet,curRP,i,v,_lp)]; if(!url)return; const a=document.createElement("a");a.href=url; a.download=`RP_line${i+1}_${l.s}.mp3`;a.click(); } /* ═══════════════════════════════════════════*/ /* PROGRESS / ERROR HELPERS*/ /* ═══════════════════════════════════════════*/ function showProg(t){ document.getElementById("pw").style.display="block"; document.getElementById("pf").className="prog-fill"+(t==="gen"?" gen":""); } function hideProg(){ document.getElementById("pw").style.display="none"; document.getElementById("pf").style.width="0%"; } function setProg(t,i,total,lbl){ const pct=Math.round(((i+1)/total)*100); document.getElementById("pl").textContent=lbl; document.getElementById("pp").textContent=pct+"%"; document.getElementById("pf").style.width=pct+"%"; } function showErr(m){const e=document.getElementById("err");e.textContent=m;e.className="err show";} function hideErr(){document.getElementById("err").className="err";} 

/* ---- OET extensions ---- */

// ===================== OET EXTENSIONS =====================
(function oetExtensions(){
  // ====== CONFIG: set this to your GitHub Pages base URL once hosted ======
  window.PREFETCH_BASE_URL = window.PREFETCH_BASE_URL || "";
  // e.g. "https://<your-username>.github.io/oet-voice-cache"
  // =======================================================================

  window.tryPrefetch = async function(key){
    if (!window.PREFETCH_BASE_URL) return null;
    try {
      var base = window.PREFETCH_BASE_URL.replace(/\/$/, "");
      var r = await fetch(base + "/" + key + ".mp3", {cache: "force-cache"});
      if (!r.ok) return null;
      var blob = await r.blob();
      return URL.createObjectURL(blob);
    } catch(e) {
      return null;
    }
  };

  // --------- IndexedDB audio cache (per-browser, persistent across reloads) ---------
  // Stores generated MP3 blobs keyed by ckey(). Survives Safari close/reopen.
  // Falls through silently in private mode or on quota errors.
  var _IDB_NAME = 'oet-voice-cache-db';
  var _IDB_STORE = 'mp3';
  var _idbDbPromise = null;
  function _idbOpen(){
    if (_idbDbPromise) return _idbDbPromise;
    _idbDbPromise = new Promise(function(resolve){
      try {
        if (typeof indexedDB === 'undefined') { resolve(null); return; }
        var req = indexedDB.open(_IDB_NAME, 1);
        req.onupgradeneeded = function(){ req.result.createObjectStore(_IDB_STORE); };
        req.onsuccess = function(){ resolve(req.result); };
        req.onerror = function(){ resolve(null); };
        req.onblocked = function(){ resolve(null); };
      } catch(e){ resolve(null); }
    });
    return _idbDbPromise;
  }
  async function _idbGetBlob(key){
    var db = await _idbOpen();
    if (!db) return null;
    return new Promise(function(resolve){
      try {
        var tx = db.transaction(_IDB_STORE, 'readonly');
        var req = tx.objectStore(_IDB_STORE).get(key);
        req.onsuccess = function(){ resolve(req.result || null); };
        req.onerror = function(){ resolve(null); };
      } catch(e){ resolve(null); }
    });
  }
  async function _idbPutBlob(key, blob){
    var db = await _idbOpen();
    if (!db) return;
    return new Promise(function(resolve){
      try {
        var tx = db.transaction(_IDB_STORE, 'readwrite');
        tx.objectStore(_IDB_STORE).put(blob, key);
        tx.oncomplete = function(){ resolve(); };
        tx.onerror = function(){ resolve(); };
        tx.onabort = function(){ resolve(); };
      } catch(e){ resolve(); }
    });
  }
  window._idbGetBlob = _idbGetBlob;
  window._idbPutBlob = _idbPutBlob;

  // Enumerate all keys in the mp3 store (for the stats badge popup).
  async function _idbAllKeys(){
    var db = await _idbOpen();
    if (!db) return [];
    return new Promise(function(resolve){
      try {
        var tx = db.transaction(_IDB_STORE, 'readonly');
        var req = tx.objectStore(_IDB_STORE).getAllKeys();
        req.onsuccess = function(){ resolve(req.result || []); };
        req.onerror = function(){ resolve([]); };
      } catch(e){ resolve([]); }
    });
  }
  async function _idbTotalBytes(){
    var db = await _idbOpen();
    if (!db) return 0;
    return new Promise(function(resolve){
      try {
        var tx = db.transaction(_IDB_STORE, 'readonly');
        var req = tx.objectStore(_IDB_STORE).getAll();
        req.onsuccess = function(){
          var total = 0;
          (req.result || []).forEach(function(b){ if (b && b.size) total += b.size; });
          resolve(total);
        };
        req.onerror = function(){ resolve(0); };
      } catch(e){ resolve(0); }
    });
  }
  window._idbAllKeys = _idbAllKeys;
  window._idbTotalBytes = _idbTotalBytes;

  // Unified audio loader — checks caches in order:
  //   1. IndexedDB  (zero network, zero credits)
  //   2. GitHub Pages prefetch  (zero credits)
  //   3. TTS API (ElevenLabs / OpenAI)  (uses credits)
  // The result is saved back to IndexedDB so the next reload is free.
  // `prov` lets callers route the TTS generation to a specific provider
  // (ElevenLabs vs OpenAI) on a per-line basis, so Doctor and Patient can
  // each use a voice from a different provider. Falls back to global
  // `provider` if omitted.
  window.loadOrGenerate = async function(key, text, voice, instr, prov){
    // 1. IDB hit
    try {
      var cachedBlob = await _idbGetBlob(key);
      if (cachedBlob) return URL.createObjectURL(cachedBlob);
    } catch(e){}

    // 2. GitHub Pages prefetch
    try {
      var pfUrl = await tryPrefetch(key);
      if (pfUrl) {
        // Also stash into IDB for offline / next-visit reuse
        try {
          var pfResp = await fetch(pfUrl);
          var pfBlob = await pfResp.blob();
          _idbPutBlob(key, pfBlob);
        } catch(e){}
        return pfUrl;
      }
    } catch(e){}

    // 3. Generate via TTS (costs credits — but only this once per key)
    var url = await generateAudio(text, voice, instr, prov);
    try {
      var ttsResp = await fetch(url);
      var ttsBlob = await ttsResp.blob();
      _idbPutBlob(key, ttsBlob);  // fire-and-forget
    } catch(e){}
    return url;
  };

  // --------- Prewarm: restore in-memory `cached` dict from IDB on load ---------
  // Without this, the 🔒 indicator icons disappear on every reload because
  // `cached = {}` is empty — even though the IDB audio blobs are still there.
  // Here we walk the lines of the current (set, rp), probe IDB for each
  // key, and populate `cached[key]` with a fresh object URL so the UI
  // reflects what's actually available offline. Fires on initApp and on
  // every buildChips() call (switchSet / switchRP / setVoice), but is
  // debounced so at most one pass runs at a time.
  var _prewarmInFlight = false;
  async function prewarmCacheFromIDB(){
    if (_prewarmInFlight) return;
    _prewarmInFlight = true;
    try {
      if (typeof SETS === 'undefined' || typeof curSet === 'undefined') return;
      var rp = SETS[curSet] && SETS[curSet].rps && SETS[curSet].rps[curRP];
      if (!rp || !rp.lines) return;
      var lines = rp.lines;
      var changed = false;
      for (var i = 0; i < lines.length; i++) {
        var l = lines[i];
        var isDoc = l.s === "Doctor";
        var v = isDoc ? docVoice : patVoice;
        var prov = isDoc ? docProvider : patProvider;
        if (!v) continue;
        var key = ckey(curSet, curRP, i, v, prov);
        if (cached[key]) continue;
        var blob = null;
        try { blob = await _idbGetBlob(key); } catch(e){}
        if (blob) {
          try { cached[key] = URL.createObjectURL(blob); changed = true; } catch(e){}
        }
      }
      if (changed) {
        if (typeof renderDial === 'function') { try { renderDial(); } catch(e){} }
        if (typeof updateBtns === 'function') { try { updateBtns(); } catch(e){} }
      }
    } finally {
      _prewarmInFlight = false;
    }
  }
  window.prewarmCacheFromIDB = prewarmCacheFromIDB;

  // --------- IDB status badge (iPhone-friendly diagnostic) ---------
  // A small pill displayed near the 키 변경 button showing how many of the
  // current RP's lines are present in IndexedDB under the currently-selected
  // voices. Green = all cached, orange = partial, gray = empty.
  // Tapping the pill shows a full breakdown popup (total blob count + MB).
  function updateIDBBadge(){
    var badge = document.getElementById('oet-idb-badge');
    if (!badge) return;
    try {
      if (typeof SETS === 'undefined' || typeof curSet === 'undefined'
          || typeof ckey !== 'function') {
        badge.textContent = '💾 –';
        return;
      }
      var rp = SETS[curSet] && SETS[curSet].rps && SETS[curSet].rps[curRP];
      if (!rp || !rp.lines) { badge.textContent = '💾 –'; return; }
      var lines = rp.lines;
      var total = lines.length, cachedN = 0;
      for (var i = 0; i < lines.length; i++) {
        var l = lines[i];
        var isDoc = l.s === 'Doctor';
        var v = isDoc ? docVoice : patVoice;
        var prov = isDoc ? docProvider : patProvider;
        if (!v) continue;
        var key = ckey(curSet, curRP, i, v, prov);
        if (cached[key]) cachedN++;
      }
      badge.textContent = '💾 ' + cachedN + '/' + total;
      var bg;
      if (cachedN === 0) bg = 'rgba(107,114,128,.85)';
      else if (cachedN < total) bg = 'rgba(245,158,11,.90)';
      else bg = 'rgba(16,185,129,.90)';
      badge.style.background = bg;
    } catch(e){}
  }
  window.updateIDBBadge = updateIDBBadge;

  // Detailed popup: queries IDB directly and shows per-RP breakdown.
  async function showIDBDetails(){
    var existing = document.getElementById('oet-idb-panel');
    if (existing) { existing.remove(); return; }
    var panel = document.createElement('div');
    panel.id = 'oet-idb-panel';
    panel.style.cssText = 'position:fixed;top:110px;right:8px;z-index:999997;'
      + 'padding:12px 14px;border-radius:10px;max-width:280px;'
      + 'background:rgba(17,24,39,.96);color:#e2e8f0;'
      + 'border:1px solid #232d42;'
      + 'font:400 12px/1.45 system-ui,sans-serif;'
      + 'box-shadow:0 4px 16px rgba(0,0,0,.45);'
      + '-webkit-tap-highlight-color:transparent;cursor:pointer';
    panel.innerHTML =
      '<div style="font-weight:600;margin-bottom:6px;font-size:13px">'
      + '💾 IndexedDB 캐시</div>'
      + '<div id="oet-idb-body" style="color:#cbd5e1">조회 중…</div>'
      + '<div style="margin-top:10px;font-size:11px;color:#94a3b8">탭하면 닫힘</div>';
    panel.addEventListener('click', function(){ panel.remove(); });
    document.body.appendChild(panel);

    try {
      var keys = await _idbAllKeys();
      var bytes = await _idbTotalBytes();
      var mb = (bytes/1024/1024).toFixed(2);
      // Breakdown by (set, rp, provider)
      var byRP = {};
      keys.forEach(function(k){
        var m = /^(\d+)_(\d+)_\d+_[^_]+_(.+)$/.exec(k);
        if (!m) return;
        var label = 'Set'+(parseInt(m[1])+1)+' · RP'+(parseInt(m[2])+1)+' ('+m[3]+')';
        byRP[label] = (byRP[label] || 0) + 1;
      });
      var breakdown = Object.keys(byRP).sort().map(function(k){
        return '<div style="display:flex;justify-content:space-between;margin:2px 0">'
          + '<span>'+k+'</span><span style="font-weight:600">'+byRP[k]+'</span></div>';
      }).join('');
      if (!breakdown) breakdown = '<div style="color:#94a3b8">(비어있음)</div>';
      var body = document.getElementById('oet-idb-body');
      if (body) {
        body.innerHTML =
          '<div style="margin-bottom:8px">전체 <b>' + keys.length + '</b>개 · '
          + '<b>' + mb + ' MB</b></div>'
          + '<div style="border-top:1px solid #232d42;padding-top:6px;font-size:11px;'
          + 'max-height:240px;overflow-y:auto">'
          + breakdown + '</div>';
      }
    } catch(e) {
      var body2 = document.getElementById('oet-idb-body');
      if (body2) body2.textContent = '오류: ' + (e && e.message || e);
    }
  }
  window.showIDBDetails = showIDBDetails;

  // --------- Playback controls: skip +/- 5s, play/pause ---------
  // `curAudio` is declared at the top of the main script block as
  //   let ..., curAudio=null, ...;
  // Classic-script `let` at top level is in script scope (NOT on window),
  // but this IIFE lives in the same <script>/bundle so it reads it via
  // closure over the script scope. Same trick as `cached`, `ckey`, etc.
  window.skipAudio = function(delta){
    try {
      if (typeof curAudio === 'undefined' || !curAudio) return;
      var t = (curAudio.currentTime || 0) + delta;
      if (t < 0) t = 0;
      var dur = curAudio.duration;
      if (dur && isFinite(dur) && t > dur) t = Math.max(0, dur - 0.01);
      curAudio.currentTime = t;
    } catch(e){}
  };
  window.togglePlayPause = function(){
    try {
      if (typeof curAudio === 'undefined' || !curAudio) return;
      if (curAudio.paused) { var p = curAudio.play(); if (p && p.catch) p.catch(function(){}); }
      else { curAudio.pause(); }
    } catch(e){}
  };
  // Exposes the state the controls UI needs to render (bar visibility +
  // play/pause label + time readout). Returns {exists:false} when there's
  // no active audio or the last one has ended, so the bar can auto-hide.
  window.getAudioState = function(){
    try {
      if (typeof curAudio === 'undefined' || !curAudio) return {exists:false};
      if (curAudio.ended) return {exists:false};
      return {
        exists: true,
        paused: !!curAudio.paused,
        currentTime: curAudio.currentTime || 0,
        duration: (isFinite(curAudio.duration) ? curAudio.duration : 0)
      };
    } catch(e){ return {exists:false}; }
  };

  window.generateAllAndZip = async function(){
    if (typeof JSZip === "undefined") {
      if (typeof showErr === "function") showErr("⚠️ JSZip 로드 실패.");
      else alert("JSZip 로드 실패");
      return;
    }
    if (typeof hideErr === "function") hideErr();
    window.cancelled = false;

    var total = 0;
    for (var si=0; si<SETS.length; si++)
      for (var ri=0; ri<SETS[si].rps.length; ri++)
        total += SETS[si].rps[ri].lines.length;

    var btn = document.getElementById("bulkBtn");
    var genBtn = document.getElementById("genBtn");
    if (btn) btn.disabled = true;
    if (genBtn) genBtn.disabled = true;
    if (typeof showProg === "function") showProg("gen");

    var done = 0, generated = 0, prefetched = 0;
    var zip = new JSZip();

    try {
      for (var si=0; si<SETS.length; si++) {
        for (var ri=0; ri<SETS[si].rps.length; ri++) {
          var lines = SETS[si].rps[ri].lines;
          for (var li=0; li<lines.length; li++) {
            if (window.cancelled) throw new Error("cancelled");
            var l = lines[li];
            var v = (l.s === "Doctor") ? docVoice : patVoice;
            var _lp = (l.s === "Doctor") ? docProvider : patProvider;
            var key = ckey(si, ri, li, v, _lp);

            if (typeof setProg === "function") {
              setProg("gen", done, total,
                "ZIP " + (done+1) + "/" + total + "  (Set" + (si+1) + " RP" + (ri+1) + " line" + (li+1) + ")");
            }

            var url = cached[key];
            if (!url) {
              url = await tryPrefetch(key);
              if (url) prefetched++;
              else { url = await generateAudio(l.t, v, l.instr || "", _lp); generated++; }
              cached[key] = url;
            }

            var resp = await fetch(url);
            var blob = await resp.blob();
            zip.file(key + ".mp3", blob);
            done++;
          }
        }
      }

      if (typeof setProg === "function") setProg("gen", total-1, total, "Zipping ...");
      var content = await zip.generateAsync({type:"blob"});
      var a = document.createElement("a");
      a.href = URL.createObjectURL(content);
      a.download = "oet_mp3_bundle_" + provider + ".zip";
      document.body.appendChild(a);
      a.click();
      a.remove();

      if (typeof showErr === "function") {
        showErr("✅ ZIP 완성  ·  신규 생성 " + generated + "개 · 서버 캐시 " + prefetched + "개");
      }
    } catch(e) {
      if (typeof showErr === "function") showErr("⚠️ Bulk ZIP 중단: " + e.message);
      else console.error(e);
    } finally {
      if (btn) btn.disabled = false;
      if (genBtn) genBtn.disabled = false;
      if (typeof hideProg === "function") hideProg();
      if (typeof renderDial === "function") renderDial();
    }
  };
})();
